import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/api';
import { Package, DollarSign, ShoppingCart, Users, TrendingUp } from 'lucide-react';
import './AdminDashboard.css';

function AdminDashboard() {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      setLoading(true);
      const response = await adminService.getDashboard();
      setDashboard(response.data);
      setError('');
    } catch (err) {
      console.error('Dashboard error:', err);
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    if (!amount && amount !== 0) return '₹0.00';
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  if (error) {
    return <div className="error-message">{error}</div>;
  }

  if (!dashboard) {
    return <div className="error-message">No dashboard data available</div>;
  }

  const { stats, products, partners, recentSales } = dashboard;

  return (
    <div className="admin-dashboard">
      <div className="dashboard-header">
        <h1>Admin Dashboard</h1>
        <p className="subtitle">Overview of your business performance</p>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#e8f5e9' }}>
            <Package size={24} color="#4caf50" />
          </div>
          <div className="stat-info">
            <h3>Total Products</h3>
            <p className="stat-value">{stats.totalProducts || 0}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#e3f2fd' }}>
            <DollarSign size={24} color="#2196f3" />
          </div>
          <div className="stat-info">
            <h3>Total Revenue</h3>
            <p className="stat-value">{formatCurrency(stats.totalRevenue)}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#fff3e0' }}>
            <ShoppingCart size={24} color="#ff9800" />
          </div>
          <div className="stat-info">
            <h3>Total Sales</h3>
            <p className="stat-value">{stats.totalSales || 0}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#fce4ec' }}>
            <TrendingUp size={24} color="#e91e63" />
          </div>
          <div className="stat-info">
            <h3>Commission Paid</h3>
            <p className="stat-value">{formatCurrency(stats.totalCommissionPaid)}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#f3e5f5' }}>
            <Users size={24} color="#9c27b0" />
          </div>
          <div className="stat-info">
            <h3>Active Partners</h3>
            <p className="stat-value">{stats.activePartners || 0}</p>
          </div>
        </div>
      </div>

      {/* Top Partners */}
      {partners && partners.length > 0 && (
        <div className="dashboard-section">
          <h2>Top Partners</h2>
          <div className="table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Partner Name</th>
                  <th>Company</th>
                  <th>Total Sales</th>
                  <th>Revenue</th>
                  <th>Commission</th>
                </tr>
              </thead>
              <tbody>
                {partners.map((partner) => (
                  <tr key={partner.partnerId}>
                    <td>
                      <div>
                        <div className="partner-name">{partner.partnerName}</div>
                        <div className="partner-email">{partner.partnerEmail}</div>
                      </div>
                    </td>
                    <td>{partner.partnerCompany || 'N/A'}</td>
                    <td>{partner.totalSales}</td>
                    <td className="amount">{formatCurrency(partner.totalRevenue)}</td>
                    <td className="amount">{formatCurrency(partner.totalCommission)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Recent Sales */}
      {recentSales && recentSales.length > 0 && (
        <div className="dashboard-section">
          <h2>Recent Sales</h2>
          <div className="table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Product</th>
                  <th>Partner</th>
                  <th>Buyer</th>
                  <th>Amount</th>
                  <th>Commission</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {recentSales.map((sale) => (
                  <tr key={sale.saleId}>
                    <td>{formatDate(sale.saleDate)}</td>
                    <td>{sale.productName}</td>
                    <td>{sale.partnerName}</td>
                    <td>
                      <div>
                        <div>{sale.buyerName}</div>
                        <div className="buyer-email">{sale.buyerEmail}</div>
                      </div>
                    </td>
                    <td className="amount">{formatCurrency(sale.saleAmount)}</td>
                    <td className="amount">{formatCurrency(sale.commissionAmount)}</td>
                    <td>
                      <span className={`status-badge status-${sale.paymentStatus.toLowerCase()}`}>
                        {sale.paymentStatus}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Products Summary */}
      {products && products.length > 0 && (
        <div className="dashboard-section">
          <h2>Your Products</h2>
          <div className="products-grid">
            {products.map((product) => (
              <div key={product.productId} className="product-card">
                <h3>{product.productName}</h3>
                <p className="product-description">{product.description}</p>
                <div className="product-info">
                  <div className="product-price">{formatCurrency(product.price)}</div>
                  <div className="product-commission">{product.commissionPercentage}% Commission</div>
                </div>
                <div className={`product-status ${product.isActive ? 'active' : 'inactive'}`}>
                  {product.isActive ? 'Active' : 'Inactive'}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Empty State */}
      {(!products || products.length === 0) && (!recentSales || recentSales.length === 0) && (
        <div className="empty-state">
          <Package size={64} color="#ccc" />
          <h3>No Data Yet</h3>
          <p>Start by adding products to see your dashboard come to life!</p>
        </div>
      )}
    </div>
  );
}

export default AdminDashboard;
